import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.assertEquals;
public class SimpleTest {
    @Test
    public void testX() {
        assertEquals("foo", "bar", "reason"); // this could be just fail("reason")
        assertEquals("foo", "foo", "other reason"); // this should be removed
        assertEquals(next("foo"), "bar"); // wrong argument order
        assertEquals("bar", next("foo")); // good
    }

    private String next(String in) {
        return "bar";
    }
}


