import org.testng.annotations.Test;
import org.testng.Assert;
public class SimpleTest {
    @Test
    public void testX() {
        Assert.assertEquals("foo", "bar", "reason"); // this could be just fail("reason")
        Assert.assertEquals("foo", "foo", "other reason"); // this should be removed
        Assert.assertEquals("bar", next("foo")); // wrong argument order
        Assert.assertEquals(next("foo"), "bar"); // good
    }

    private String next(String in) {
        return "bar";
    }
}


import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.assertEquals;
public class SimpleTest {
    private static String CONST = "foo";
    @Test
    public void testX() {
        assertEquals(CONST, "bar", "reason"); // wrong argument order
        assertEquals("foo", CONST, "other reason"); // OK
        assertEquals(next("foo"), "b" + "a" + "r"); // wrong argument order
        assertEquals("b" + "a" + "r", next("foo")); // good
    }
    private String next(String in) {
        return "bar";
    }
}
